package com.tegonal.variist.generators

/**
 * Represents a [SemiOrderedLikeArgsGenerator] where some part/aspect of [T] is always in the
 * same order and finite before repeating and another part of [T] is undefined (could be ordered and finite,
 * could be ordered and infinite, could be random).
 *
 * @param T the type of values generated by `this` [SemiOrderedLikeArgsGenerator].
 *
 * @since 2.0.0
 */
interface SemiOrderedArgsGenerator<out T> : SemiOrderedLikeArgsGenerator<T>
